import{_ as i,C as h,o as E,c as s,j as t,a as e,b as l,w as r,E as d,a4 as n,a5 as A}from"./chunks/framework.sOZL8giL.js";const k=JSON.parse('{"title":"成本与可靠性","description":"","frontmatter":{},"headers":[],"relativePath":"07-生产实践/03-成本与可靠性.md","filePath":"07-生产实践/03-成本与可靠性.md","lastUpdated":1774181700000}'),B={name:"07-生产实践/03-成本与可靠性.md"};function b(C,a,p,u,D,c){const o=h("Mermaid");return E(),s("div",null,[a[2]||(a[2]=t("h1",{id:"成本与可靠性",tabindex:"-1"},[e("成本与可靠性 "),t("a",{class:"header-anchor",href:"#成本与可靠性","aria-label":'Permalink to "成本与可靠性"'},"​")],-1)),a[3]||(a[3]=t("blockquote",null,[t("p",null,[e("本章是 "),t("strong",null,"Hermes Engineering 系列"),e("第 7 模块的第 3 章。")])],-1)),a[4]||(a[4]=t("p",null,"Token 预算、分层模型、断点续传、优雅降级——让 Agent 系统在成本可控的前提下可靠运行。",-1)),a[5]||(a[5]=t("hr",null,null,-1)),a[6]||(a[6]=t("h2",{id:"token-预算控制",tabindex:"-1"},[e("Token 预算控制 "),t("a",{class:"header-anchor",href:"#token-预算控制","aria-label":'Permalink to "Token 预算控制"'},"​")],-1)),(E(),l(n,null,{default:r(()=>[d(o,{id:"mermaid-15",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20A%5BSession%20%E9%A2%84%E7%AE%97%3Cbr%2F%3E%E6%95%B4%E4%B8%AA%E4%BC%9A%E8%AF%9D%E6%80%BB%E9%A2%84%E7%AE%97%5D%20--%3E%20B%5BTask%20%E9%A2%84%E7%AE%97%3Cbr%2F%3E%E5%8D%95%E6%AC%A1%E4%BB%BB%E5%8A%A1%E9%A2%84%E7%AE%97%5D%0A%20%20%20%20B%20--%3E%20C%5BAgent%20%E9%A2%84%E7%AE%97%3Cbr%2F%3E%E5%8D%95%E4%B8%AAAgent%E9%A2%9D%E5%BA%A6%5D%0A%20%20%20%20C%20--%3E%20D%7B%E4%BD%BF%E7%94%A8%E7%8E%87%7D%0A%20%20%20%20D%20--%3E%7C%3C80%25%7C%20E%5B%E6%AD%A3%E5%B8%B8%E8%BF%90%E8%A1%8C%5D%0A%20%20%20%20D%20--%3E%7C80-95%25%7C%20F%5B%E8%BD%BB%E5%BE%AE%E5%BB%B6%E8%BF%9F%3Cbr%2F%3E%E6%B8%90%E8%BF%9B%E5%BC%8F%E9%99%90%E6%B5%81%5D%0A%20%20%20%20D%20--%3E%7C%E2%89%A595%25%7C%20G%5B%E9%87%8D%E5%BA%A6%E9%99%90%E6%B5%81%5D%0A%20%20%20%20D%20--%3E%7C100%25%7C%20H%7B%E6%A8%A1%E5%BC%8F%7D%0A%20%20%20%20H%20--%3E%7C%E7%A1%AC%E9%99%90%E5%88%B6%7C%20I%5B%E7%9B%B4%E6%8E%A5%E6%8B%92%E7%BB%9D%5D%0A%20%20%20%20H%20--%3E%7C%E8%BD%AF%E9%99%90%E5%88%B6%7C%20J%5B%E8%AD%A6%E5%91%8A%E5%90%8E%E7%BB%A7%E7%BB%AD%5D%0A%20%20%20%20H%20--%3E%7C%E5%AE%A1%E6%89%B9%E6%A8%A1%E5%BC%8F%7C%20K%5B%E6%9A%82%E5%81%9C%E7%AD%89%E4%BA%BA%E5%B7%A5%E7%A1%AE%E8%AE%A4%5D%0A%20%20%20%20style%20E%20fill%3A%234a9%0A%20%20%20%20style%20F%20fill%3A%23f96%0A%20%20%20%20style%20G%20fill%3A%23f66%0A%20%20%20%20style%20I%20fill%3A%23f66%0A"})]),fallback:r(()=>[...a[0]||(a[0]=[e(" Loading... ",-1)])]),_:1})),a[7]||(a[7]=A('<blockquote><p>💡 <strong>图解：</strong> 预算控制是背压机制——不是到 100% 才断崖式停止，而是从 80% 开始渐进限流，给用户和系统缓冲时间。</p></blockquote><p>每个 Token 都是钱。生产环境必须有预算控制——设定硬上限超了就停。</p><h3 id="多层预算" tabindex="-1">多层预算 <a class="header-anchor" href="#多层预算" aria-label="Permalink to &quot;多层预算&quot;">​</a></h3><p>Session 预算（整个会话总预算）→ Task 预算（单次任务）→ Agent 预算（单个 Agent）。分层让每个 Agent 都有自己的额度，不会相互挤占。</p><p>硬限制 vs 软限制 vs 审批模式：对外 API 用硬限制（防止单个用户烧光资源），内部工具用软限制（任务能完成更重要），关键任务用审批模式（超预算了让人确认是否继续）。</p><h3 id="背压机制" tabindex="-1">背压机制 <a class="header-anchor" href="#背压机制" aria-label="Permalink to &quot;背压机制&quot;">​</a></h3><p>预算压力增大时不是突然停止，而是渐进式限流——使用率 80% 时轻微延迟，95% 时重度限流。用户感知到响应变慢知道该省着点用，平滑降级有缓冲时间。</p><h3 id="预算优化" tabindex="-1">预算优化 <a class="header-anchor" href="#预算优化" aria-label="Permalink to &quot;预算优化&quot;">​</a></h3><p>上下文压缩减少输入 Token。工具响应转文件减少重复传输。缓存高频查询结果。选择合适大小的模型——不是所有任务都需要最大模型。</p><hr><h2 id="分层模型策略" tabindex="-1">分层模型策略 <a class="header-anchor" href="#分层模型策略" aria-label="Permalink to &quot;分层模型策略&quot;">​</a></h2>',11)),(E(),l(n,null,{default:r(()=>[d(o,{id:"mermaid-49",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20A%5B%E4%BB%BB%E5%8A%A1%E8%BF%9B%E5%85%A5%5D%20--%3E%20B%7B%E8%B7%AF%E7%94%B1%E7%AD%96%E7%95%A5%7D%0A%20%20%20%20B%20--%3E%7C%E6%84%8F%E5%9B%BE%E5%88%86%E7%B1%BB%2F%E6%A0%BC%E5%BC%8F%E8%BD%AC%E6%8D%A2%3Cbr%2F%3E%E7%AE%80%E5%8D%95%E9%97%AE%E7%AD%94%7C%20C%5BTier%201%3A%20%E5%B0%8F%E6%A8%A1%E5%9E%8B%3Cbr%2F%3EGPT-4o-mini%3Cbr%2F%3E%E6%88%90%E6%9C%AC%E6%9C%80%E4%BD%8E%5D%0A%20%20%20%20B%20--%3E%7C%E4%BB%A3%E7%A0%81%E7%94%9F%E6%88%90%3Cbr%2F%3E%E4%B8%AD%E7%AD%89%E6%8E%A8%E7%90%86%7C%20D%5BTier%202%3A%20%E4%B8%AD%E6%A8%A1%E5%9E%8B%3Cbr%2F%3EGPT-4o%3Cbr%2F%3E%E6%88%90%E6%9C%AC%E4%B8%AD%E7%AD%89%5D%0A%20%20%20%20B%20--%3E%7C%E5%A4%8D%E6%9D%82%E6%8E%A8%E7%90%86%2F%E5%85%B3%E9%94%AE%E5%86%B3%E7%AD%96%3Cbr%2F%3E%E9%87%8D%E8%A6%81%E4%BB%BB%E5%8A%A1%7C%20E%5BTier%203%3A%20%E5%A4%A7%E6%A8%A1%E5%9E%8B%3Cbr%2F%3EGPT-4%2FClaude%20Opus%3Cbr%2F%3E%E6%88%90%E6%9C%AC%E6%9C%80%E9%AB%98%5D%0A%20%20%20%20C%20--%3E%7C%E7%BD%AE%E4%BF%A1%E5%BA%A6%E4%B8%8D%E5%A4%9F%EF%BC%9F%7C%20D%0A%20%20%20%20D%20--%3E%7C%E7%BD%AE%E4%BF%A1%E5%BA%A6%E4%B8%8D%E5%A4%9F%EF%BC%9F%7C%20E%0A%20%20%20%20C%20--%3E%20F%5B%E8%BF%94%E5%9B%9E%E7%BB%93%E6%9E%9C%5D%0A%20%20%20%20D%20--%3E%20F%0A%20%20%20%20E%20--%3E%20F%0A%20%20%20%20style%20C%20fill%3A%234a9%0A%20%20%20%20style%20D%20fill%3A%238cf%0A%20%20%20%20style%20E%20fill%3A%23f96%0A"})]),fallback:r(()=>[...a[1]||(a[1]=[e(" Loading... ",-1)])]),_:1})),a[8]||(a[8]=A('<blockquote><p>💡 <strong>图解：</strong> 不是所有任务都需要最强模型——分层策略让 80% 的请求用便宜模型跑通，只把最贵的模型留给真正需要的场景。</p></blockquote><p>不是所有任务都需要最强大最昂贵的模型。分层模型策略：用便宜模型做简单任务，贵模型留给真正需要的场景。</p><table tabindex="0"><thead><tr><th>层级</th><th>模型</th><th>适用场景</th><th>成本</th></tr></thead><tbody><tr><td><strong>Tier 1</strong></td><td>小模型（GPT-4o-mini）</td><td>意图分类、格式转换、简单问答</td><td>最低</td></tr><tr><td><strong>Tier 2</strong></td><td>中模型（GPT-4o）</td><td>代码生成、中等复杂度推理</td><td>中等</td></tr><tr><td><strong>Tier 3</strong></td><td>大模型（GPT-4、Claude Opus）</td><td>复杂推理、关键决策</td><td>最高</td></tr></tbody></table><p>路由策略：先用小模型尝试，如果小模型置信度不够再升级到大模型。或者按任务类型预设——分类任务用小模型，生成任务用大模型。</p><h3 id="推理档位" tabindex="-1">推理档位 <a class="header-anchor" href="#推理档位" aria-label="Permalink to &quot;推理档位&quot;">​</a></h3><p>同一模型有不同推理强度档位。LangChain 的实践：规划阶段用 X-High（最容易决定成败），实现阶段用 High（不需要过度推演），验证阶段再用 X-High（需要谨慎）。分段式算力分配把分数从 53.9% 推到 66.5%。</p><hr><h2 id="断点续传" tabindex="-1">断点续传 <a class="header-anchor" href="#断点续传" aria-label="Permalink to &quot;断点续传&quot;">​</a></h2><p>长任务可能运行数小时。如果中间失败了从头再来成本太高。</p><h3 id="持久化状态" tabindex="-1">持久化状态 <a class="header-anchor" href="#持久化状态" aria-label="Permalink to &quot;持久化状态&quot;">​</a></h3><p>Agent 的执行状态持久化到数据库：当前步骤、已完成子任务、中间结果。失败后可以从最近的检查点恢复而不是从头开始。</p><h3 id="clean-state-原则" tabindex="-1">Clean State 原则 <a class="header-anchor" href="#clean-state-原则" aria-label="Permalink to &quot;Clean State 原则&quot;">​</a></h3><p>Anthropic 的方案：每次会话结束前必须让代码库回到可运行状态。如果 Agent 引入错误且修复无果，用 Git 回退到上一轮稳定提交。这提供了低成本容错能力。</p><h3 id="功能清单驱动" tabindex="-1">功能清单驱动 <a class="header-anchor" href="#功能清单驱动" aria-label="Permalink to &quot;功能清单驱动&quot;">​</a></h3><p>JSON 格式的功能清单，每次只做一个功能。Agent 醒来后读取清单、找到 <code>passes</code> 仍为 <code>false</code> 的条目、实现并测试、提交更新。默认失败原则——必须完成测试才允许改为 <code>true</code>。</p><hr><h2 id="优雅降级" tabindex="-1">优雅降级 <a class="header-anchor" href="#优雅降级" aria-label="Permalink to &quot;优雅降级&quot;">​</a></h2><p>Agent 系统中的任何组件都可能失败——LLM API 不可用、工具超时、数据库连接断开。系统需要优雅降级而不是直接崩溃。</p><h3 id="降级策略" tabindex="-1">降级策略 <a class="header-anchor" href="#降级策略" aria-label="Permalink to &quot;降级策略&quot;">​</a></h3><table tabindex="0"><thead><tr><th>故障类型</th><th>降级策略</th></tr></thead><tbody><tr><td><strong>LLM API 不可用</strong></td><td>切换到备用模型或缓存的响应</td></tr><tr><td><strong>工具超时</strong></td><td>返回错误让 Agent 尝试其他方法</td></tr><tr><td><strong>向量数据库不可用</strong></td><td>回退到关键词搜索</td></tr><tr><td><strong>预算耗尽</strong></td><td>停止 Agent 并返回已完成的部分结果</td></tr></tbody></table><h3 id="熔断器" tabindex="-1">熔断器 <a class="header-anchor" href="#熔断器" aria-label="Permalink to &quot;熔断器&quot;">​</a></h3><p>下游服务故障时不傻傻重试。连续失败 N 次后进入熔断状态——拒绝请求、等待恢复、试探性放行。Shannon 的实现：失败 5 次后熔断 60 秒，60 秒后允许一个试探请求。</p><h3 id="重试与退避" tabindex="-1">重试与退避 <a class="header-anchor" href="#重试与退避" aria-label="Permalink to &quot;重试与退避&quot;">​</a></h3><p>指数退避：0.5s → 1s → 2s → 4s。设置最大重试次数（通常 3 次）。区分可重试错误（网络超时）和不可重试错误（参数错误）。</p><hr><h2 id="成本监控" tabindex="-1">成本监控 <a class="header-anchor" href="#成本监控" aria-label="Permalink to &quot;成本监控&quot;">​</a></h2><h3 id="实时追踪" tabindex="-1">实时追踪 <a class="header-anchor" href="#实时追踪" aria-label="Permalink to &quot;实时追踪&quot;">​</a></h3><p>按 Session、Task、Agent 维度追踪 Token 消耗。实时告警——Token 消耗突然飙升时立即通知。</p><h3 id="成本归因" tabindex="-1">成本归因 <a class="header-anchor" href="#成本归因" aria-label="Permalink to &quot;成本归因&quot;">​</a></h3><p>每个 API 调用记录：输入 Token、输出 Token、缓存 Token、模型名称、调用者（哪个 Agent/Task）。支持按维度聚合分析——哪个 Agent 最烧钱？哪个工具调用成本最高？</p><h3 id="优化目标" tabindex="-1">优化目标 <a class="header-anchor" href="#优化目标" aria-label="Permalink to &quot;优化目标&quot;">​</a></h3><p>定期审查成本报告。识别高成本低价值的操作——可能是不必要的工具调用、重复的搜索、冗余的上下文。优化后重新评估成本变化。</p><hr><h2 id="可靠性保障" tabindex="-1">可靠性保障 <a class="header-anchor" href="#可靠性保障" aria-label="Permalink to &quot;可靠性保障&quot;">​</a></h2><h3 id="幂等性" tabindex="-1">幂等性 <a class="header-anchor" href="#幂等性" aria-label="Permalink to &quot;幂等性&quot;">​</a></h3><p>Agent 的工具调用应该尽可能幂等——同样的输入多次执行结果相同。非幂等操作（发邮件、创建资源）需要去重机制。</p><h3 id="超时控制" tabindex="-1">超时控制 <a class="header-anchor" href="#超时控制" aria-label="Permalink to &quot;超时控制&quot;">​</a></h3><p>每层都有超时：工具调用超时（单次操作）、Agent 超时（单次任务）、Session 超时（整个会话）。超时后执行降级策略而不是无限等待。</p><h3 id="健康检查" tabindex="-1">健康检查 <a class="header-anchor" href="#健康检查" aria-label="Permalink to &quot;健康检查&quot;">​</a></h3><p>定期检查各组件状态：LLM API 可达性、工具服务可用性、数据库连接。健康检查失败时触发告警和自动切换。</p><hr><h2 id="本章要点" tabindex="-1">本章要点 <a class="header-anchor" href="#本章要点" aria-label="Permalink to &quot;本章要点&quot;">​</a></h2><ul><li>Token 预算：多层预算 + 背压机制 + 优化策略</li><li>分层模型：便宜模型做简单任务，贵模型留给复杂推理</li><li>断点续传：持久化状态 + Clean State + 功能清单驱动</li><li>优雅降级：熔断器 + 重试退避 + 降级策略</li><li>成本监控：实时追踪 + 成本归因 + 定期审查</li></ul><hr><p><strong>上一章</strong>: <a href="./02-安全与权限.html">安全与权限</a></p><hr><h2 id="模块总结" tabindex="-1">模块总结 <a class="header-anchor" href="#模块总结" aria-label="Permalink to &quot;模块总结&quot;">​</a></h2><p>生产实践系列全部完结，共 3 章：</p><table tabindex="0"><thead><tr><th>章节</th><th>主题</th><th>核心概念</th></tr></thead><tbody><tr><td>1</td><td>可观测性</td><td>Trace/Metrics/Logs、Trace 即反馈</td></tr><tr><td>2</td><td>安全与权限</td><td>沙箱隔离、L1-L4 分级、审计日志</td></tr><tr><td>3</td><td>成本与可靠性</td><td>Token 预算、分层模型、断点续传、优雅降级</td></tr></tbody></table><hr><p><a href="/">← 返回首页</a></p>',51))])}const q=i(B,[["render",b]]);export{k as __pageData,q as default};
